import React from "react";
import "./Alerts.css"; // optional CSS for styling alerts

const Alerts = ({ alerts }) => {
  return (
    <div className="alerts-container">
      {alerts.map((alert, index) => (
        <div key={index} className="alert-box">
          {alert}
        </div>
      ))}
    </div>
  );
};

export default Alerts;
